document.addEventListener("DOMContentLoaded",()=>{const a=document.querySelectorAll(".counter__value");if(!a.length)return;const l=t=>{const n=t.textContent.trim().replace(",","."),e=parseFloat(n);if(Number.isNaN(e))return;const s=!Number.isInteger(e),c=Math.round(2e3/(1e3/60));let o=0;const f=r=>1-Math.pow(1-r,4),u=()=>{o++;const r=f(o/c),i=e*r;t.textContent=s?i.toFixed(1):Math.round(i),o<c?requestAnimationFrame(u):t.textContent=s?e.toFixed(1):e};requestAnimationFrame(u)},m={root:null,threshold:.25},d=new IntersectionObserver((t,n)=>{t.forEach(e=>{e.isIntersecting&&(l(e.target),n.unobserve(e.target))})},m);a.forEach(t=>d.observe(t))});
